const Q_ECONOMICS_1995=[{"id": "objective>Economics>1995>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ultimate objective of economics is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">make effort to understand how the economy works</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make the best use of scarce resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">organize production at the lowest cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decide under what circumstances the government should intervene in the economy</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ultimate objective of economics is to make the best use of scarce resources. Economics is a social science that deals with the production, distribution, and consumption of goods and services. It studies how individuals, businesses, governments, and nations make choices on allocating resources to satisfy their wants and needs, trying to determine how these groups should organize and coordinate efforts to achieve maximum output. The concept of scarcity is central to economics, as it refers to the basic economic problem - the gap between limited resources and theoretically limitless wants.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>1995>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the circular flow of income above, the direction of flow of payments for consumption purchases is shown by the arrow </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">L</div>", "<div style=\"font-family:Cambria;font-size:17px;\">M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The flow of payment in the circular flow of income is indicated by M. In the circular flow of income of a two sector economy, the firms and households, which leads to a certain flow of money in the economy.  <br/> Household provide the firms with the factors of production, namely land, labour, capital and enterprise that generates goods and services, and consumers spend their income on the consumption of these goods and services. The firms then make factor payments to households in form of of rent, wages, interest and profit.</div>", "topic": "THEORY OF PRODUCTION (1) : INTRODUCTION"}, {"id": "objective>Economics>1995>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A student in obu'pu secondary school discovers that he simultaneously needs a biro, an exercise book, an eraser and a ruler, but that he can purchase only one of these items. What is the first thing he is expected to do?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">check how much money he has </div>", "<div style=\"font-family:Cambria;font-size:17px;\">find out which is the cheapest of the items</div>", "<div style=\"font-family:Cambria;font-size:17px;\">draw up a scale of preference </div>", "<div style=\"font-family:Cambria;font-size:17px;\">weigh the opportunity cost of each item against the others</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Scales of preference is a table which shows the relationship between price and item of an individual. It also shows an individual according to his or her piority. The first thing he should do is to draw up a scale of preference.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT"}, {"id": "objective>Economics>1995>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What to produce in any society is determined by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">expenditure of the people on different commodities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">competition among the different producers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">competition among the different consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">supply and demand in the factor markets.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The central problems of what and how much to produce; how to produce and for whom to produce are determined by the free price mechanism i.e the interplay and interaction of demand and supply.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>1995>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The active intervention of the central authorities in the management of a country's economy rests upon the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">failure of the market forces to produce satisfactory results</div>", "<div style=\"font-family:Cambria;font-size:17px;\">superiority of the centrally</div>", "<div style=\"font-family:Cambria;font-size:17px;\">result-oriented nature of the private enterprise economy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost minimization strategy of a mixed economy</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The aim is to improve economic welfare of the economy generally due to the failure of market forces.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>1995>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The problems of conducting census include </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">high rate of rural-urban migration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poor geographical distribution of population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high birth rate in the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poor town planning in urban areas</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Conducting a census in a country with a high rate of rural-urban migration can be challenging. This is because the constant movement of people from rural to urban areas and vice versa can make it difficult to get an accurate count of the population in a specific area at a given time. The other options do not directly relate to the challenges of conducting a census.</div>", "topic": "POPULATION : INTRODUCTION"}, {"id": "objective>Economics>1995>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An ageing population is a population </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">with a high dependency ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">with many young people </div>", "<div style=\"font-family:Cambria;font-size:17px;\">in which the number of old persons is increasing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">that is dominated by very old people</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ageing population also known as decreasing or stationery population means an increasing percentage of old people while the percentage of children and workers are decreasing.</div>", "topic": "POPULATION : POPULATION DENSITY, AGEING POPULATION"}, {"id": "objective>Economics>1995>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The population of Ohaha L.G.A was 480 000 in december 1980, out of which 60% were females. if within one year no births were recorded, but 5% of the males died, what will be the population of the L.G.A. in december 1981?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">96,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">192,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">288,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">470,400</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Population = 480,000 <br/>  <br/> Females = 60% <br/> 60%  x 480,000 <br/> = 288,000 <br/>  <br/> Males = 480,000 - 288,000 <br/> = 192,000 <br/> Number of males that died = 5 %  x 192,000 <br/> = 9,600 <br/> Total number of males = 192,000 - 9,600 <br/> = 182,400 <br/>  <br/> Total population = No of males + No of females <br/> =  288,000 +182,400 <br/> = 470,400</div>", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE"}, {"id": "objective>Economics>1995>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is meant by labour supply?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">number of people in working population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">number of men and hours they work</div>", "<div style=\"font-family:Cambria;font-size:17px;\">number of hours during which the middle aged persons work</div>", "<div style=\"font-family:Cambria;font-size:17px;\">number of workforce multiplied by the hours they work.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Labour supply refers to the total hours that workers or employees are willing to work at a given wage rate. It is not just about the number of people in the working population, but also about the number of hours they are willing to work. Therefore, the correct answer is 'number of workforce multiplied by the hours they work.'</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR"}, {"id": "objective>Economics>1995>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The advantages which firms obtain directly from expanding their operations are reffered to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">internal economies of scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">external economies of scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economies of localization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economies of resource allocation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Internal economics of scale are the economics enjoyed by a firm that operates on a large scale. The internal economies of large scale are also the advantages firms obtain directly from increases or expansion of their outputs.</div>", "topic": "THEORY OF PRODUCTION (1) : SCALE OF PRODUCTION"}, {"id": "objective>Economics>1995>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The factor of production that has the highest degree of mobility is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">land</div>", "<div style=\"font-family:Cambria;font-size:17px;\">labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">entrepreneurship</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The factor of production that has the highest degree of mobility is labour. Mobility of labour is the ability of workers to move in order to find and qualify for better jobs. Labour mobility is important for the efficiency of the labour market, as it helps to match workers with jobs. The other factors of production (land, capital, entrepreneurship) are generally less mobile. For example, land is immobile, capital is often tied up in investments and not easily moved, and entrepreneurship is often tied to specific individuals or groups.</div>", "topic": "FACTORS OF PRODUCTION & THEIR THEORIES : WAGES"}, {"id": "objective>Economics>1995>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Any payment to a factor of production in excess of what is necessary to keep that factor in its present employment is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">real income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic rent </div>", "<div style=\"font-family:Cambria;font-size:17px;\">real wage</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economic rent is the extra income a worker receives above the minimum level they need in order to work. It is calculated as: total revenue (output) - explicit cost - opportunity cost of input.</div>", "topic": "FACTORS OF PRODUCTION & THEIR THEORIES : RENT & INTEREST"}, {"id": "objective>Economics>1995>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">No of workers</td><td style=\"border:1px solid black;text-align:center;\"> Total output(Units)</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\"> 24</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\"> 46</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\"> 60</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\"> 84</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\"> 95</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\"> 110</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">7</td><td style=\"border:1px solid black;text-align:center;\"> 115</td></tr></table></div> <br/> In the table above, the marginal product of the 2nd worker and the average product of the 5th worker respectively are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">23 and 20</div>", "<div style=\"font-family:Cambria;font-size:17px;\">22 and 19</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14 and 19</div>", "<div style=\"font-family:Cambria;font-size:17px;\">11 and 20</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mp @ 2 = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">∆TP</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">∆Q</span> i.e <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">TP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - TP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></span> <br/>  <br/> = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">46 - 24</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2 - 1</span> <br/>  <br/> = 22 <br/>  <br/>  <br/> AP @ 5 = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">TP</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">Q</span> <br/>  <br/> = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">95</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">5</span> <br/>  <br/> = 19</div>", "topic": "THEORY OF PRODUCTION (2) : CONCEPTS OF PRODUCTION"}, {"id": "objective>Economics>1995>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given that TC = TFC + TVC and TR = AR x Q, profit is equal to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">(AR + Q) - TFC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">(TFC + TVC) / Q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">(AR x Q) - TC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">(TC x Q) / AR</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Profit is calculated as: Total revenue - Total cost i.e TR - TC <br/> Note that TR = P ( AR) x Q and TC = TFC + TVC <br/> Therefore Profit = P ( AR) x Q - TFC + TVC</div>", "topic": "THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION"}, {"id": "objective>Economics>1995>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The opportunity cost of the use of productive resources which a producer owns and so does not pay for constitutes </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a fixed cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an implicit cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a variable cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a prime cost</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Implicit costs are the inputed value of entrepreneur's own resources and services. It is incurred by the owner of the firm in production.</div>", "topic": "THE CONCEPT OF COST & REVENUE : EXPLICIT AND IMPLICIT COSTS"}, {"id": "objective>Economics>1995>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The effect of changes in the condition of demand on a demand schedule with the price constant is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a movement along the demand curve </div>", "<div style=\"font-family:Cambria;font-size:17px;\">deflation of the demand curve </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hyperbola formation by the demand curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shift of the demand curve</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A shift in the demand curve is also known as a change in the demand curve. There is a change in the demand curve when the demand curve shift to an entirely new position when price remains constant.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>1995>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statement is TRUE of the effect changes in demand and supply on price?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a decrease in supply will lead to a fall in price and and a fall in the quatity bought and sold</div>", "<div style=\"font-family:Cambria;font-size:17px;\">and increase in demand will lead to a fall in price and in the quantity bought and sold</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in demand will lead to a rise in price and in the quantity bought and sold </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in supply will lead to a fall in price and a rise in the quantity bought and sold</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If supply increases while demand remains constants, there will be an excess supply over demand. This will lead to a decrease in the equilibrium price and increase in the equilibrium quantity.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>1995>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a free market economy, available resources are more efficiency allocated by complete reliance on </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">development planning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">strategic planning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital budgeting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price system</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a free market or free enterprise , the price are determined by the price system/mechanism i.e the forces of demand and supply.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>1995>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In order to maximize his profit, a businessman who faces a very elastic demand for his products is advised to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">slightly increase the price of his products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slightly reduce the price of his products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">leave his prices unchanged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">discriminate his prices</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A firm or businessmen or monopoly will have to look at his elasticity before he fixes his price. If the elasticity is elastic, he will have to reduce his price and if the elasticity is inelastic, he will have to increase his price in order to earn higher revenue</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>1995>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the elasticity of demand for commodity X, if at a price of #25 the quantity demanded is 80 and when the price is reduced to #20 the quantity demanded is 100?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.25</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.45</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.25</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.15</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">e = ∆q/∆p  x p/q <br/>  <br/> where ∆q = q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> ∆p = p<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - p<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> p = 1st price <br/> q = 1st quantity <br/>  <br/> e = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">100 - 80</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">20 - 25</span>  x <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">25</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">80</span> <br/>  <br/>  e = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">20</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">5</span>  x <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">25</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">80</span> <br/>  <br/> e = - 1.25 since price elasticity is always positive, then e = 1.25</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>1995>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If y represents the income earned by workers in a factory, find the range of their income which satisfies the following inequality: 4y - 300 > 500.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">y > 300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">y > 250</div>", "<div style=\"font-family:Cambria;font-size:17px;\">y > 200</div>", "<div style=\"font-family:Cambria;font-size:17px;\">y > 150</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The inequality 4y - 300 > 500 can be solved by adding 300 to both sides to get 4y > 800, then dividing both sides by 4 to get y > 200. Therefore, the range of income that satisfies the inequality is y > 200.</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : INTRODUCTION"}, {"id": "objective>Economics>1995>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Both in the short run and in the long run, a firm maximizes its profits when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">MC = MR</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AC = MC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AVC = AC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC = AVC</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A firm maximizes profit in the short run and long run when the marginal revenue equals marginal cost.</div>", "topic": "THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION"}, {"id": "objective>Economics>1995>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above, the total revenue of the monopolist is given by the area</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">OQ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>MP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>MTP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">OQ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>TP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">OQ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The total revenue represent the total income derived from the monopoly i.e Price  x quantity <br/> The highest price is P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> and the quantity is Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>. Therefore, TR = OP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>TQ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>1995>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Stocking small quantities of a variety of goods is a function of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">manufacturer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wholesaler</div>", "<div style=\"font-family:Cambria;font-size:17px;\">retailer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A retailer is a person who buys from the whosaler in bulk and sell to the retailer in small quantities.</div>", "topic": "DISTRIBUTIVE TRADE : THE RETAILER"}, {"id": "objective>Economics>1995>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a joint stock company, preference shareholders are those who receive</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">high dividends when profits are high and little or nothing when profits are low</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a fixed rate of dividend and have the first claim on the net profits of the company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the remaining profits after all other shareholders have been paid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dividends quarterly when others receive annually.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Preference shareholders receive dividend payment before common shareholders. Preference shareholders do not enjoy voting rights like their common shareholder counterparts do.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>1995>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major reason for the survival of small shops despite competition from large business enterprise is becasue of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the small capital outlay involved </div>", "<div style=\"font-family:Cambria;font-size:17px;\">regularity and constant supply of commodities by them</div>", "<div style=\"font-family:Cambria;font-size:17px;\">their local services and longer hours of operation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">their level of managerial competence</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Small firms are often relatively easy to establish, and generally do not require complex rules and procedures to set them up.</div>", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP"}, {"id": "objective>Economics>1995>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major advantages of public enterprises is that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">they are highly subsidized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they are largest employers of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">their operations are highly standardized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they take prompt decisions and actions.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Public enterprises are often the largest employers of labour because they are usually large-scale operations that require a significant workforce. They are often involved in key sectors of the economy such as utilities, transportation, and healthcare, which require a large number of employees to operate effectively.</div>", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS"}, {"id": "objective>Economics>1995>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When public enterprises become commercialized, it means that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the products of the enterprises are further subsidized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they are expected to operate with the primary aim of making profits </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the government has decided to divest itself of such enterprises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the staff of the enterprises will be laid off. </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commercialisation is a policy geared towards making state-owned enterprises to become more efficient and profit-oriented. The policy makes it possible for public enterprises to become more viable and effective.</div>", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS"}, {"id": "objective>Economics>1995>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements are TRUE of agriculture in Nigeria? <br/> I. it provides food for the growing population  <br/> II. a large proportion of the population is engaged in agriculture <br/> III. agricultural products are used as raw materials by the local industries <br/> IV. it serves as sources of heavy equipment to local industries</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The contribution of agriculture are: provision of food, provision of raw materials, revenue for farmers and government, provision of employment, provision of foreign exchange, provision of market for industrial goods etc.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>1995>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In recent times, agriculture in Nigeria tends to lose its vital labour force as a result of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lack of an effective agricultural policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">emploment opportunities in the oil sector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rural-urban drift</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low prices of agricultural products</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The movement of able bodied men and youth out of rural areas to urban centres has worsened the development of agriculture. Agriculture is thus left to old men and women who cannot produce food for the increasing population.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>1995>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The government can influence the prices of agricultural products by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fixing minimum prices when agricultural output is low</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixing maximum prices in years of bumper harvests</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the use of buffer stock and stabilization funds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">paying all farmers producing identical crops a uniform amount of money.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The government can influence the prices of agricultural products by the use of buffer stock and stabilization funds.</div>", "topic": "AGRICULTURE IN WEST AFRICA : MARKETING BOARDS"}, {"id": "objective>Economics>1995>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The crucial factors which determine the location of petroleum refineries in Nigeria are availability of raw materials and </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political consideration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nearness to source of power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">labour</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The crucial factors which determine the location of petroleum refineries in Nigeria are availability of raw materials and labour. Labour is a crucial factor because the operation of a refinery requires skilled and unskilled labour. The availability of labour can influence the location of a refinery.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>1995>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Infant industries denote industries which</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are introducing new products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are too young to compete in the world market </div>", "<div style=\"font-family:Cambria;font-size:17px;\">produce baby food and mother care products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are allowed time enough to mature for recognition</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Infant industries is one that is new and in its early stages of development and thus, not yet capable of competing against established industry competitors.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>1995>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When compared with a labour intensive industry a capital-intensive industry employs more</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">workers than capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">workers than machinery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raw materials than capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">machinery than workers</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Capital intensive industry requires relatively large amounts of money for machinery and infrastructure to produce a good or service.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>1995>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major source of Nigeria's foreign exchange is the export of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">skilled manpower </div>", "<div style=\"font-family:Cambria;font-size:17px;\">palm karnel and cocoa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crude oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">groundnuts and cutton</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major source of Nigeria's foreign exchange is the export of crude oil. Nigeria is one of the largest oil producers in the world and the largest in Africa. The oil sector provides the largest source of foreign exchange earnings for Nigeria.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>1995>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important goal of OPEC is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">present a united front for the purpose of raising prices of crude oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bring utility among the petroleum exporting states</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure political stability among member states</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure that rules on quota production are strictly followed</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most important goal of OPEC (Organization of the Petroleum Exporting Countries) is to present a united front for the purpose of raising prices of crude oil. OPEC's mission is to coordinate and unify the petroleum policies of its member countries and ensure the stabilization of oil markets in order to secure an efficient, economic and regular supply of petroleum to consumers, a steady income to producers and a fair return on capital for those investing in the petroleum industry.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF"}, {"id": "objective>Economics>1995>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The central bank's expansionary monetary policy is justified as a period </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">when the inflation rate is high and the economy is experiencing a boom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">of economic depression accompanied by low capacity utilization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">when trade unions are clamouring for hight wages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">when the price of crude petroleum is rising</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Expansionary monetary policy is used by the central bank to reduce unemployment and boost growth during hard economic times by lowing interest rates, increases demand etc.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>1995>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sharp increases in the prices of most goods and services during the last quarter of 1994 in Nigeria were mainly due to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ban on importation of foreign goods </div>", "<div style=\"font-family:Cambria;font-size:17px;\">population upsurge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the introduction of value added tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in transport costs</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The VAT creates higher costs for businesses and it encourage tax evasion. Passed along costs lead to higher prices.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>1995>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The best method to curb inflation in Nigeria is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reduce importation of commodities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the general level of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce the level of money supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">set up price control boards</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Inflation is a general increase in prices and fall in the purchasing value of money. It is often caused by an increase in the supply of money. Therefore, reducing the level of money supply is a direct method to curb inflation. This can be achieved through monetary policy tools such as increasing interest rates, increasing reserve requirements, or directly reducing the amount of money in circulation.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>1995>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A bank is said to be distressed when it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is unable to deal with the central bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has a low capital base</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has low level of deposits</div>", "<div style=\"font-family:Cambria;font-size:17px;\">experiences serious liquidity crisis</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bank distress is a condition when the banking system as a whole has negative capital and current profit are insufficient to cover losses to such an extent, that the banking system is unable to generate internally positive capital.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>1995>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One method through which the central bank can restrict the commercial banks' power of credit expansion is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">demand for increased special deposits</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease the cash ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">buy securities in the open market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce the rates of interest at which banks borrow from it</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Special deposit is an instrument of monetary policy which is used to restrict lending. The central bank can order the commercial banks to have special deposits, usually a percentage of the bank's deposits, to be made with it. This is intended to control control credit and is often used during the period of inflation to reduce cash with banks.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>1995>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the cheapest for the government in improving the welfare of its citizens?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">subsidy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">income supplement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">donation to specific projects </div>", "<div style=\"font-family:Cambria;font-size:17px;\">wages increase </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Income supplement is the cheapest for the government in improving the welfare of its citizens. This is because income supplements directly increase the income of the citizens, thereby improving their welfare. Other options like subsidy, donation to specific projects, and wages increase may involve additional costs such as administrative costs, monitoring costs, and potential market distortions.</div>", "topic": "PUBLIC FINANCE : BUDGET"}, {"id": "objective>Economics>1995>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is mostly used to determine the cost of living?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marginal changes in prices </div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer price index</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prices of imported and exported commodities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">producer price index</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cost of living is measured by the price index. Consumer price index measures relative changes in consumer prices over time.</div>", "topic": "NATIONAL INCOME : DIFFERENCE BETWEEN STANDARD OF LIVING & COST OF LIVING"}, {"id": "objective>Economics>1995>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer questions below <br/> The diagram explains the effect of government's imposition of an indirect tax on a good characterized by zero price elasticity of demand. <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The total tax revenue is represented by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>EHP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">O</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>HQ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">O</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>EQ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">O</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>ED<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">O</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">cost = 0P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>HQ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> and revenue = 0P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>EQ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> <br/> Therefore, Total revenue ( profit ) = 0P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>HQ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> - 0P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>EQ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> <br/> =  P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>EHP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">O</span>. <br/> </div>", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX"}, {"id": "objective>Economics>1995>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer questions below <br/> The diagram explains the effect of government's imposition of an indirect tax on a good characterized by zero price elasticity of demand. <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> the tax imposed is borne</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">totally by the consumer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">totally by the producer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equally by both the consumer and the producer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">by the government</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since the government's impose an indirect tax characterized by zero price elasticity of demand, then consumers will bear the entire burden of a tax.</div>", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX"}, {"id": "objective>Economics>1995>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ajanka, a medical student entitled to an annual allowance of #6,000 decides to leave the university to take up a job where he earns #7,000 per annum. By this singular act, the national income level will </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase by #1,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease by #7,000 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase by #7,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase by #13,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As the income of a consumer increases, the consumption also increase which will increase the level of national income.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>1995>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An increasing population might be of economic benefit to a country if </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the female population is greater than the male population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the dependency ratio is increasing as the total population increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a continuously higher proportion falls into the working class category</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the rural urban and urban proportion are balanced.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the number of working ( active or independent) population is high, there will be an increase in economic growth which will benefit the economic but there will be challenges for job creation.</div>", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION"}, {"id": "objective>Economics>1995>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The demands made on each other by the agricultural and industrial sectors as the economy grows are reflected in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">backward and forward linkages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">horizontal and vertical linkages </div>", "<div style=\"font-family:Cambria;font-size:17px;\">vertical linkages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">functional linkages</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Linkages arises from the interdependence between agriculture and industry through the use of productive inputs. Agriculture draws some raw materials like sugarcan, cotton etc from the industry.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>1995>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Foreign exchange rate in a free market economy is determined by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the government </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the central bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand and supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercial banks</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a free floating exchange rate system, exchange rates are determined by demand and supply. Exchage rates are determined by demand and supply in a managed float system, but governments intervene as buyers or sellers of currencies in an effort to influence exchange rates.</div>", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE"}, {"id": "objective>Economics>1995>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The primary objective of all international economic organizations it to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ensure that third world countries get a better share of the world's resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promote international economic cooperation for the mutual benefit of all members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enforce structural adjustment programmes on less developed countries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">encourage exports from the developed to the less developed countries</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To faciltate the expansion and balanced growth of international trade, and to contribute thereby to the promotion and maintenance of high level of employment and real income and to the development of the productive resources of all members as primary objectives of economic policy.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC"}];
